+// ============================================================================
+// Field descriptor
+// ============================================================================
+
+/// Field configuration for a dataclass field
+pub fn Field(comptime T: type) type {
+    return struct {
+        const Self = @This();
+
+        name: []const u8,
+        field_type: type = T,
+        default: ?T = null,
+        default_factory: ?*const fn () T = null,
